package web.abort.internal

import js.array.jsArrayOf
import js.errors.toJsError
import js.reflect.Reflect
import web.abort.AbortController
import web.abort.AbortSignal
import web.abort.abortEvent
import web.events.Event
import web.events.EventHandler
import web.events.addHandler

internal fun safeAny(
    signal1: AbortSignal?,
    signal2: AbortSignal,
): AbortSignal {
    if (signal1 == null)
        return signal2

    if (signal1.aborted)
        return signal1

    if (signal2.aborted)
        return signal2

    return if (Reflect.has(AbortSignal, "any")) {
        AbortSignal.any(jsArrayOf(signal1, signal2))
    } else {
        legacySafariAny(signal1, signal2)
    }
}

private fun legacySafariAny(
    signal1: AbortSignal,
    signal2: AbortSignal,
): AbortSignal {
    val controller = AbortController()
    val handlers = mutableListOf<() -> Unit>()
    val abortHandler = EventHandler<Event, AbortSignal, AbortSignal, _> { event ->
        handlers.forEach { it() }

        controller.abort(event.currentTarget.reason?.toJsError())
    }

    handlers += signal1.abortEvent.addHandler(abortHandler)
    handlers += signal2.abortEvent.addHandler(abortHandler)

    return controller.signal
}

package io.ktor.openapi

import kotlinx.serialization.Serializable
import org.jetbrains.kotlin.name.ClassId
import org.jetbrains.kotlin.name.Name
import org.jetbrains.kotlin.name.StandardClassIds

@Serializable
enum class JsonPrimitive {
    STRING,
    NUMBER,
    INTEGER,
    BOOLEAN,
}

fun findJsonPrimitiveType(name: String): JsonPrimitive? {
    val classId = ClassId(
        StandardClassIds.BASE_KOTLIN_PACKAGE,
        Name.identifier(name)
    )
    return classId.toJsonType()
}

fun ClassId.toJsonType(): JsonPrimitive? =
    when(this) {
        // Integer types
        StandardClassIds.Int,
        StandardClassIds.UInt,
        StandardClassIds.Short,
        StandardClassIds.UShort,
        StandardClassIds.Byte,
        StandardClassIds.UByte,
        StandardClassIds.Long,
        StandardClassIds.ULong ->
            JsonPrimitive.INTEGER

        // Number types
        StandardClassIds.Float,
        StandardClassIds.Double,
        StandardClassIds.Number ->
            JsonPrimitive.NUMBER

        // Boolean type
        StandardClassIds.Boolean ->
            JsonPrimitive.BOOLEAN

        // String types
        StandardClassIds.String,
        StandardClassIds.Char ->
            JsonPrimitive.STRING

        // For all other classes, treat as custom object schema
        else -> null
    }

package maestro.orchestra

import maestro.js.JsEngine
import maestro.orchestra.util.Env.evaluateScripts

// Note: The appId config is only a yaml concept for now. It'll be a larger migration to get to a point
// where appId is part of MaestroConfig (and factored out of MaestroCommands - eg: LaunchAppCommand).
data class MaestroConfig(
    val appId: String? = null,
    val name: String? = null,
    val tags: List<String>? = emptyList(),
    val ext: Map<String, Any?> = emptyMap(),
    val onFlowStart: MaestroOnFlowStart? = null,
    val onFlowComplete: MaestroOnFlowComplete? = null,
    val properties: Map<String, String> = emptyMap(),
) {

    fun evaluateScripts(jsEngine: JsEngine): MaestroConfig {
        return copy(
            appId = appId?.evaluateScripts(jsEngine),
            name = name?.evaluateScripts(jsEngine),
            properties = properties.mapValues { (_, v) -> v.evaluateScripts(jsEngine) },
            onFlowComplete = onFlowComplete?.evaluateScripts(jsEngine),
            onFlowStart = onFlowStart?.evaluateScripts(jsEngine),
        )
    }

}

data class MaestroOnFlowComplete(val commands: List<MaestroCommand>) {
    fun evaluateScripts(jsEngine: JsEngine): MaestroOnFlowComplete {
        return this
    }
}

data class MaestroOnFlowStart(val commands: List<MaestroCommand>) {
    fun evaluateScripts(jsEngine: JsEngine): MaestroOnFlowStart {
        return this
    }
}

package com.badoo

import com.badoo.reaktive.samplemppmodule.Counter
import com.badoo.reaktive.samplemppmodule.Counter.Event
import kotlinx.browser.document
import org.w3c.dom.HTMLElement
import kotlin.time.Duration.Companion.seconds

fun main() {
    document.addEventListener(type = "DOMContentLoaded", callback = { onLoaded() })
}

private fun onLoaded() {
    val counter = Counter()

    val valueText = document.getElementById("value") as HTMLElement
    val loader = document.getElementById("loader") as HTMLElement
    val incrementButton = document.getElementById("button-increment") as HTMLElement
    val decrementButton = document.getElementById("button-decrement") as HTMLElement
    val resetButton = document.getElementById("button-reset") as HTMLElement
    val fibonacciButton = document.getElementById("button-fibonacci") as HTMLElement
    val increaseAfter1s = document.getElementById("button-increase-after-1s") as HTMLElement
    val increaseEvery1s = document.getElementById("button-increase-every-1s") as HTMLElement

    counter.state.subscribe { state ->
        valueText.innerHTML = state.value.toString()
        loader.hidden = !state.isLoading
    }

    incrementButton.onclick = { counter.onEvent(Event.Increment) }
    decrementButton.onclick = { counter.onEvent(Event.Decrement) }
    resetButton.onclick = { counter.onEvent(Event.Reset) }
    fibonacciButton.onclick = { counter.onEvent(Event.Fibonacci) }

    increaseAfter1s.onclick = {
        counter.onEvent(Event.IncrementAfter(1.seconds))
    }

    increaseEvery1s.onclick = {
        counter.onEvent(Event.IncrementEvery(1.seconds))
    }
}

