internal class ByteBufferFetcher(
    private val data: ByteBuffer,
    private val options: Options,
) : Fetcher {

    override suspend fun fetch(): FetchResult {
        return SourceFetchResult(
            source = ImageSource(
                source = data.asSource().buffer(),
                fileSystem = options.fileSystem,
                metadata = ByteBufferMetadata(data),
            ),
            mimeType = null,
            dataSource = DataSource.MEMORY,
        )
    }

    class Factory : Fetcher.Factory<ByteBuffer> {

        override fun create(
            data: ByteBuffer,
            options: Options,
            imageLoader: ImageLoader,
        ): Fetcher {
            return ByteBufferFetcher(data, options)
        }
    }
}

internal fun ByteBuffer.asSource() = object : Source {
    private val buffer = this@asSource.slice()
    private val len = buffer.capacity()

    override fun close() = Unit

    override fun read(sink: Buffer, byteCount: Long): Long {
        if (buffer.position() == len) return -1
        val pos = buffer.position()
        val newLimit = (pos + byteCount).toInt().coerceAtMost(len)
        buffer.limit(newLimit)
        return sink.write(buffer).toLong()
    }

    override fun timeout() = Timeout.NONE
}

package coil3.fetch

import coil3.ImageLoader
import coil3.Uri
import coil3.decode.DataSource
import coil3.decode.ImageSource
import coil3.request.Options
import coil3.util.MimeTypeMap
import coil3.util.extension
import okio.Path.Companion.toPath
import okio.openZip

internal class JarFileFetcher(
    private val uri: Uri,
    private val options: Options,
) : Fetcher {

    override suspend fun fetch(): FetchResult {
        val path = uri.path.orEmpty()
        val delimiterIndex = path.indexOf('!')
        check(delimiterIndex != -1) { "Invalid jar:file URI: $uri" }

        val jarPath = path.substring(0, delimiterIndex).toPath()
        val filePath = path.substring(delimiterIndex + 1, path.length).toPath()

        return SourceFetchResult(
            source = ImageSource(filePath, options.fileSystem.openZip(jarPath)),
            mimeType = MimeTypeMap.getMimeTypeFromExtension(filePath.extension),
            dataSource = DataSource.DISK,
        )
    }

    class Factory : Fetcher.Factory<Uri> {
        override fun create(
            data: Uri,
            options: Options,
            imageLoader: ImageLoader,
        ): Fetcher? {
            if (!isApplicable(data)) return null
            return JarFileFetcher(data, options)
        }

        private fun isApplicable(data: Uri): Boolean {
            return data.scheme == "jar:file"
        }
    }
}

package dev.detekt.core.reporting

import dev.detekt.api.Issue
import dev.detekt.api.Severity
import java.nio.file.Path

internal fun printIssues(issues: Map<String, List<Issue>>, basePath: Path): String =
    buildString {
        issues.forEach { (key, nestedIssues) ->
            append(key)
            append("\n")
            nestedIssues.forEach {
                append("\t")
                append(it.detailed(basePath).yellow())
                append("\n")
            }
        }
    }

private const val REPORT_MESSAGE_SIZE_LIMIT = 80
private val messageReplacementRegex = Regex("\\s+")

private fun Issue.truncatedMessage(): String {
    val message = message
        .replace(messageReplacementRegex, " ")
        .trim()
    return when {
        message.length > REPORT_MESSAGE_SIZE_LIMIT -> "${message.take(REPORT_MESSAGE_SIZE_LIMIT)}(...)"
        else -> message
    }
}

private fun Issue.detailed(basePath: Path): String =
    "${severity.prefix()}: ${ruleInstance.id} - [${truncatedMessage()}] at ${location.compact(basePath)}"

internal fun Issue.Location.compact(basePath: Path): String = "${basePath.resolve(path)}:$source"

internal fun Severity.prefix() =
    when (this) {
        Severity.Error -> "e"
        Severity.Warning -> "w"
        Severity.Info -> "i"
    }

package dev.detekt.generator.printer

import dev.detekt.generator.collection.Configuration
import dev.detekt.utils.bold
