internal object ConfigurationsPrinter : DocumentationPrinter<List<Configuration>> {

    override fun print(item: List<Configuration>): String {
        if (item.isEmpty()) return ""
        return markdown {
            h4 { "Configuration options:" }
            list {
                item.forEach {
                    val defaultValues = it.defaultValue.printAsMarkdownCode()
                    val defaultAndroidValues = it.defaultAndroidValue?.printAsMarkdownCode()
                    val defaultString = if (defaultAndroidValues != null) {
                        "(default: ${code { defaultValues }}) (android default: ${code { defaultAndroidValues }})"
                    } else {
                        "(default: ${code { defaultValues }})"
                    }
                    if (it.isDeprecated()) {
                        item {
                            crossOut { code { it.name } } + " " + defaultString
                        }
                        description { "${bold { "Deprecated" }}: ${it.deprecated}" }
                    } else {
                        item {
                            code { it.name } + " " + defaultString
                        }
                    }
                    description { it.description }
                }
            }
        }
    }
}

package karakum.common

private val MINUS_LETTER = Regex("""-(\w)""")
private val PLUS_LETTER = Regex("""\+(\w)""")
private val SLASH_LETTER = Regex("""\/(\w)""")
private val UNDERSCORE_LETTER = Regex("""_(\w)""")
private val SPACE_LETTER = Regex("""\s(\w)""")

private val toUpperCase: (MatchResult) -> CharSequence = {
    it.groupValues[1].uppercase()
}

internal fun String.kebabToCamel(): String =
    replace(MINUS_LETTER, toUpperCase)
        .replace(PLUS_LETTER, toUpperCase)
        .replace(SLASH_LETTER, toUpperCase)
        .replace(SPACE_LETTER, toUpperCase)

internal fun String.snakeToCamel(): String =
    replace(UNDERSCORE_LETTER, toUpperCase)
        .replace(SPACE_LETTER, toUpperCase)

internal fun String.withDefaultLineBreaks(): String =
    replace("\r\n", "\n")

internal fun String.replaceSuffix(
    from: String,
    to: String,
): String {
    require(endsWith(from))

    return removeSuffix(from) + to
}

internal fun String.removeQuoteSurrounding(): String =
    removeSurrounding("'")
        .removeSurrounding("\"")

internal fun String.startsWithAnyQuote(): Boolean =
    startsWith("'") || startsWith("\"")

internal fun String.count(
    substring: String,
): Int {
    var index = 0
    var count = 0

    do {
        index = indexOf(substring, index)
        if (index == -1) break

        index += substring.length
        count++
    } while (true)

    return count
}

package karakum.query

class Method(
    override val source: String,
    private val external: Boolean = false,
) : Member() {
    private val typeParameters: List<String> by lazy {
        parseTypeParameters(
            source.substringBefore("(")
                .replace("Record<string, any>", "Any /* object */")
                .replace("QueryOptions<any, any, any, any>", "QueryOptions<*, *, *, *, *>")
                .replace("<any, any, any, any>", "<*, *, *, *>"),
        )
    }

    private val parameters: List<String> by lazy {
        parseParameters(source)
    }

    private val returnType: String by lazy {
        kotlinType(source.substringAfter("): "), name)
            .fixDefaultOptions()
    }

    override fun toCode(): String {
        val rt = if (returnType != "Unit") {
            ": $returnType"
        } else ""

        // TEMP
        if (shouldSkipFunction())
            return ""

        val params = parameters.joinToString(",\n")
        val modifiers = (if (external) "external" else "") + modifiers
        return "$modifiers fun ${formatParameters(typeParameters)} ${safeName(name)}($params)$rt"
    }

    private fun shouldSkipFunction(): Boolean {
        if (!external) {
            return false
        }

        if (name == "useQuery" && returnType.startsWith("Any /* useQuery<")) {
            return true
        }

        if (name == "noop" && returnType == "Unit") {
            return true
        }

        return false
    }
}

