package csstype

import js.objects.unsafeJso
import web.cssom.*

interface RuleBuilder<T : Any> : Rules {
    inline fun `@container`(
        query: ContainerQuery,
        block: T.() -> Unit,
    ) {
        set(Selector("@container $query"), unsafeJso(block))
    }

    inline fun `@container`(
        containerName: ContainerName,
        query: ContainerQuery,
        block: T.() -> Unit,
    ) {
        set(Selector("@container $containerName $query"), unsafeJso(block))
    }

    inline fun `@font-face`(
        block: FontFace.() -> Unit,
    ) {
        set(Selector("@font-face"), unsafeJso(block))
    }

    inline fun `@media`(
        query: MediaQuery,
        block: T.() -> Unit,
    ) {
        set(Selector("@media $query"), unsafeJso(block))
    }

    inline fun `@view-transition`(
        block: ViewTransition.() -> Unit,
    ) {
        set(Selector("@view-transition"), unsafeJso(block))
    }

    inline operator fun Selector.invoke(
        block: T.() -> Unit,
    ) {
        set(this, unsafeJso(block))
    }

    inline operator fun ClassName.invoke(
        block: T.() -> Unit,
    ) {
        Selector(".$this")(block)
    }

    inline operator fun String.invoke(
        block: T.() -> Unit,
    ) {
        Selector(this)(block)
    }

    inline fun and(
        className: ClassName,
        block: T.() -> Unit,
    ) {
        Selector("&.$className")(block)
    }
}

package karakum.csstype

import karakum.common.ConversionResult

private val RGB_PARAMETERS = arrayOf(
    "red" to "Int",
    "green" to "Int",
    "blue" to "Int",
    "alpha" to "Double",
)

private val OKLCH_PARAMETERS = arrayOf(
    "l" to PERCENTAGE,
    "c" to "Double",
    "h" to "Double",
    "a" to "Double",
)

internal fun colorFunctions(): ConversionResult {
    val declarations = sequenceOf(
        factory(
            COLOR,
            COLOR, // TODO: remove
            parameters = arrayOf(
                "value" to STRING,
            ),
        ),
    ).plus(
        sequenceOf(3, 4)
            .map { RGB_PARAMETERS.take(it).toTypedArray() }
            .map { parameters ->
                function(
                    name = "rgb",
                    returnType = COLOR,
                    parameters = parameters,
                    delimiter = " ",
                )
            },
    ).plus(
        sequenceOf(3, 4)
            .map { OKLCH_PARAMETERS.take(it).toTypedArray() }
            .map { parameters ->
                function(
                    name = "oklch",
                    returnType = COLOR,
                    parameters = parameters,
                    delimiter = " ",
                )
            },
    )

    return ConversionResult(
        name = "Color.functions",
        body = declarations.joinToString("\n\n"),
    )
}

package io.mockk.impl.instantiation

import kotlin.reflect.KClass

open class JvmAnyValueGenerator(
    private val voidInstance: Any,
) : AnyValueGenerator() {
    override fun anyValue(
        cls: KClass<*>,
        isNullable: Boolean,
        orInstantiateVia: () -> Any?,
    ): Any? =
        when (cls) {
            Void.TYPE.kotlin -> voidInstance
            Void::class -> voidInstance

            java.lang.Boolean::class -> false
            java.lang.Byte::class -> 0.toByte()
            java.lang.Short::class -> 0.toShort()
            java.lang.Character::class -> 0.toChar()
            java.lang.Integer::class -> 0
            java.lang.Long::class -> 0L
            java.lang.Float::class -> 0.0F
            java.lang.Double::class -> 0.0
            java.lang.Class::class -> Object::class.java

            java.util.List::class -> List<Any>(0) {}
            java.util.Map::class -> HashMap<Any, Any>()
            java.util.Set::class -> HashSet<Any>()
            java.util.ArrayList::class -> ArrayList<Any>()
            java.util.HashMap::class -> HashMap<Any, Any>()
            java.util.HashSet::class -> HashSet<Any>()

            else ->
                super.anyValue(cls, isNullable) {
                    if (cls.java.isArray) {
                        java.lang.reflect.Array
                            .newInstance(cls.java.componentType, 0)
                    } else {
                        orInstantiateVia()
                    }
                }
        }
}

package com.apollographql.apollo.compiler.codegen.java.helpers

import com.apollographql.apollo.compiler.codegen.java.JavaClassNames
import com.apollographql.apollo.compiler.codegen.java.L
import com.apollographql.apollo.compiler.codegen.java.S
import com.apollographql.apollo.compiler.codegen.java.T
import com.apollographql.apollo.compiler.codegen.java.joinToCode
import com.squareup.javapoet.CodeBlock

internal fun List<CodeBlock>.toListInitializerCodeblock(withNewLines: Boolean = false): CodeBlock {
  if (isEmpty()) {
    return CodeBlock.of("$T.emptyList()", JavaClassNames.Collections)
  }

  val newLine = if (withNewLines) "\n" else ""
  val space = if (withNewLines) "" else " "
  return CodeBlock.builder()
      .add("$T.asList($newLine", JavaClassNames.Arrays)
      .indent()
      .add(L, joinToCode(",$newLine$space"))
      .unindent()
      .add("$newLine)")
      .build()
}

internal fun List<CodeBlock>.toArrayInitializerCodeblock(): CodeBlock {
  return CodeBlock.builder()
      .add("{")
      .add(L, joinToCode(", "))
      .add("}")
      .build()
}

internal fun List<Pair<String, CodeBlock>>.toMapInitializerCodeblock(): CodeBlock {
  if (isEmpty()) {
    return CodeBlock.of("$T.emptyMap()", JavaClassNames.Collections)
  }
  return CodeBlock.builder()
      .add("new $T()", JavaClassNames.ImmutableMapBuilder)
      .apply {
        forEach {
          add(".put($S, $L)", it.first, it.second)
        }
        add(".build()")
      }
      .build()
}

package com.apollographql.apollo.compiler.codegen.kotlin.helpers

import com.squareup.kotlinpoet.CodeBlock
import com.squareup.kotlinpoet.joinToCode


internal fun List<CodeBlock>.toListInitializerCodeblock(withNewLines: Boolean = false): CodeBlock {
  if (isEmpty()) {
    return CodeBlock.of("emptyList()")
  }

  return if (withNewLines) {
    CodeBlock.builder()
        .add("listOf(\n")
        .indent()
        .add("%L", joinToCode(",\n"))
        .unindent()
        .add("\n)")
        .build()
  } else {
    CodeBlock.builder()
        .add("listOf(")
        .add("%L", joinToCode(", "))
        .add(")")
        .build()
  }
}

internal fun List<Pair<String, CodeBlock>>.toMapInitializerCodeblock(withNewLines: Boolean = false): CodeBlock {
  if (isEmpty()) {
    return CodeBlock.of("emptyMap()")
  }

  val items = map { CodeBlock.of("%S to %L", it.first, it.second) }
  return if (withNewLines) {
    CodeBlock.builder()
        .add("mapOf(\n")
        .indent()
        .add("%L", items.joinToCode(",\n"))
        .unindent()
        .add("\n)")
        .build()
  } else {
    CodeBlock.builder()
        .add("mapOf(")
        .add("%L", items.joinToCode(", "))
        .add(")")
        .build()
  }
}

package io.mockk.impl.recording

import io.mockk.Invocation
import io.mockk.Matcher
import io.mockk.impl.log.SafeToString
import kotlin.reflect.KClass

class CallRoundBuilder(
    val safeToString: SafeToString,
) {
    val signedMatchers = mutableListOf<SignedMatcher>()
    val signedCalls = mutableListOf<SignedCall>()

    fun addMatcher(
        matcher: Matcher<*>,
        sigValue: Any,
    ) {
        signedMatchers.add(SignedMatcher(matcher, sigValue))
    }

    fun addSignedCall(
        retValue: Any?,
        tempMock: Boolean,
        retType: KClass<*>,
        invocation: Invocation,
    ) {
        val signedCall =
            SignedCall(
                retValue,
                tempMock,
                retType,
                invocation.self,
                invocation.method,
                invocation.args,
                safeToString.exec { invocation.toString() },
            )

        signedCalls.add(signedCall)
    }

    fun addWasNotCalled(list: List<Any>) {
        for (self in list) {
            signedCalls.add(
                SignedCall(
                    Unit,
                    false,
                    Unit::class,
                    self,
                    WasNotCalled.method,
                    listOf(),
                    safeToString.exec { "$self wasNot Called" },
                ),
            )
        }
    }

    fun build() = CallRound(signedCalls.toList(), signedMatchers.toList())
}

package io.mockk.impl.stub

import io.mockk.MockKGateway
import io.mockk.MockKGateway.Clearer
import io.mockk.impl.log.Logger
import io.mockk.impl.log.SafeToString

class CommonClearer(
    val stubRepository: StubRepository,
    val safeToString: SafeToString,
) : Clearer {
    val log = safeToString(Logger<CommonClearer>())

    override fun clear(
        mocks: Array<out Any>,
        options: MockKGateway.ClearOptions,
    ) {
        log.debug { "Clearing ${mocks.contentToString()} mocks $options" }
        for (mock in mocks) {
            stubRepository.stubFor(mock).clear(options)
        }
    }

    override fun clearAll(
        options: MockKGateway.ClearOptions,
        currentThreadOnly: Boolean,
    ) {
        val currentThreadId = Thread.currentThread().id
        stubRepository.allStubs.forEach { stub ->
            if (currentThreadOnly && currentThreadId != stub.threadId) {
                return@forEach
            }
            val isRegularOrSpy =
                when {
                    stub is SpyKStub<*> -> stub.mockType == MockType.SPY
