package arrow.retrofit.adapter.either

import okhttp3.ResponseBody
import retrofit2.Call
import retrofit2.Callback
import retrofit2.Converter
import retrofit2.Response
import java.lang.reflect.Type

internal inline fun <E, R, T> onResponseFn(
  callback: Callback<T>,
  call: Call<T>,
  errorConverter: Converter<ResponseBody, E>,
  bodyType: Type,
  response: Response<R>,
  newResponseFn: (R, Response<R>) -> Response<T>,
  errorResponseFn: (E, Response<R>) -> Response<T>,
) {
  if (response.isSuccessful) {
    val body = response.body()
    if (body == null) {
      // if we defined Unit as body type it means we expected no response body
      // e.g. in case of 204 No Content
      if (bodyType == Unit::class.java) {
        @Suppress("UNCHECKED_CAST")
        callback.onResponse(call, newResponseFn(Unit as R, response))
      } else {
        callback.onFailure(call, IllegalStateException("Null body found!"))
      }
    } else {
      callback.onResponse(call, newResponseFn(body, response))
    }
  } else {
    val error = response.errorBody()
    if (error == null) {
      callback.onFailure(call, IllegalStateException("Null errorBody found!"))
    } else {
      try {
        val errorBody = errorConverter.convert(response.errorBody()!!)
        if (errorBody == null) {
          callback.onFailure(call, IllegalStateException("Null errorBody found!"))
        } else {
          callback.onResponse(call, errorResponseFn(errorBody, response))
        }
      } catch (e: Exception) {
        callback.onFailure(call, IllegalStateException("Failed to convert error body!", e))
      }
    }
  }
}

package org.jetbrains.compose.resources

import org.khronos.webgl.ArrayBuffer
import kotlin.wasm.unsafe.Pointer
import kotlin.wasm.unsafe.UnsafeWasmMemoryApi
import kotlin.wasm.unsafe.withScopedMemoryAllocator

@OptIn(UnsafeWasmMemoryApi::class, ExperimentalWasmJsInterop::class)
internal fun fastArrayBufferToByteArray(arrayBuffer: ArrayBuffer): ByteArray {
    val size = arrayBuffer.byteLength
    return withScopedMemoryAllocator { allocator ->
        val bufferPtr = allocator.allocate(size)
        copyArrayBufferToWasmMemory(arrayBuffer, bufferPtr.address.toInt())
        readFromLinearMemory(bufferPtr, 0, size)
    }
}

//language=js
@OptIn(ExperimentalWasmJsInterop::class)
private fun copyArrayBufferToWasmMemory(ab: ArrayBuffer, ptr: Int): Unit = js("""{
      const data = new Uint8Array(ab);
      new Uint8Array(wasmExports.memory.buffer).set(data, ptr);
}""")

@OptIn(UnsafeWasmMemoryApi::class)
private fun readFromLinearMemory(base: Pointer, offset: Int, length: Int): ByteArray {
    val bytes = ByteArray(length)
    val src = base + offset
    val intCount = length / 4
    var idx = 0
    for (i in 0 until intCount) {
        val value = (src + idx).loadInt()
        bytes[idx] = (value and 0xFF).toByte()
        bytes[idx + 1] = ((value shr 8) and 0xFF).toByte()
        bytes[idx + 2] = ((value shr 16) and 0xFF).toByte()
        bytes[idx + 3] = ((value shr 24) and 0xFF).toByte()
        idx += 4
    }
    for (i in idx until length) {
        bytes[i] = (src + i).loadByte()
    }
    return bytes
}

package karakum.cesium

internal class Enum(
    override val source: Definition,
) : Declaration(), IEnum {
    override val name: String =
        source.defaultName

    override fun toCode(): String {
        val body = source.body
            .substringAfter("\n    ")
            .removeSuffix("}")
            .replace(",\n     *", "__COMMA__\n     *")
            .split(Regex(""",\n\s+"""))
            .asSequence()
            .map { it.replace("__COMMA__\n", ",\n") }
            .flatMap { parseTopDefinition(it) }
            .map { EnumConstant(it, this) }
            .joinToString("\n\n") {
                it.toCode()
            }

        return DEFAULT_PACKAGE +
                source.doc(DocLink(this)) +
                "\n" +
                "sealed /* enum */\n" +
                "external interface $name {\n" +
                "companion object {\n\n" +
                "$body\n" +
                "}\n" +
                "}"
    }

    companion object {
        const val PREFIX = "export enum "
        const val CONST_PREFIX = "export const enum "
    }
}

// TODO: describe value in comments
internal class EnumConstant(
    override val source: Definition,
    private val parent: Enum,
) : Declaration() {
    override val name: String =
        source.body.split(" = ")[0]

    override fun toCode(): String {
        val doc = source.doc()
        val body = "val $name: ${parent.name}"

        return if (doc.isNotBlank()) {
            "$doc\n$body"
        } else {
            body
        }
    }
}

package karakum.cesium

internal class Parameter(
    body: String,
) {
    val name: String = body.substringBefore(": ")
        .removePrefix("...")
        .removeSuffix("?")
        .let { if (it == "object") "obj" else it }

    private val vararg: Boolean by lazy { "..." in body.substringBefore("{") }

    val type: String by lazy {
        val source = body.substringAfter(": ")
            .let { if (vararg) it.removeSuffix("[]") else it }

        kotlinType(source, name)
    }

    val optional: Boolean by lazy { "?:" in body.substringBefore("{") }
    private val nullable: Boolean by lazy { optional && !type.startsWith("JsAny? ") }

    var supportDefault: Boolean = true

    fun toCode(): String =
        (if (vararg) "vararg " else "") +
                " $name: $type" +
                (if (nullable && !type.endsWith("?")) "?" else "") +
                (if (optional && supportDefault) " = definedExternally" else "")
}

internal fun List<Parameter>.toCode(
    multilinePreferred: Boolean,
): String =
    when {
        size == 0 -> "()"
        size == 1 && !multilinePreferred -> "(${single().toCode()})"
        else -> {
            val params = joinToString(",\n") {
                it.toCode()
            }

            "(\n$params\n)"
        }
    }

